"use client"

import { useMemo, useState, useEffect } from "react"
import { useAuthStore } from "@/store/auth-store"
import { useDataStore } from "@/store/data-store"
import { PageHeader } from "@/components/shared/page-header"
import { Card, CardContent } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select"
import { Badge } from "@/components/ui/badge"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Search, Filter, Clock3, UserCircle2, ScrollText } from "lucide-react"
import type { UserRole } from "@/lib/types"

const ROLE_FILTERS: { value: "all" | UserRole; label: string }[] = [
  { value: "all", label: "All Roles" },
  { value: "admin", label: "Admin" },
  { value: "utility_manager", label: "Utility Managers" },
  { value: "dma_manager", label: "DMA Managers" },
]

export default function LogsPage() {
  const { currentUser } = useAuthStore()
  const { logs, utilities, fetchLogs, fetchUtilities } = useDataStore()

  const [search, setSearch] = useState("")
  const [roleFilter, setRoleFilter] = useState<"all" | UserRole>("all")

  // Fetch data on mount
  useEffect(() => {
    fetchLogs()
    fetchUtilities()
  }, [fetchLogs, fetchUtilities])

  const isAdmin = currentUser?.role === "admin"
  const isUtility = currentUser?.role === "utility_manager"

  // Find utility for utility manager
  const myUtility = isUtility ? utilities.find((u) => u.managerId === currentUser?.id) : null

  const scopedLogs = useMemo(() => {
    if (!currentUser) return []
    if (isAdmin) return logs
    if (isUtility && myUtility) {
      return logs.filter((log) => log.utilityId === myUtility.id)
    }
    return []
  }, [currentUser, isAdmin, isUtility, logs, myUtility])

  const filtered = useMemo(
    () =>
      scopedLogs
        .filter((log) => {
          const query = search.toLowerCase()
          const matchSearch =
            !query ||
            log.action.toLowerCase().includes(query) ||
            log.userName.toLowerCase().includes(query) ||
            (log.details?.toLowerCase() || "").includes(query) ||
            log.entity.toLowerCase().includes(query)

          const matchRole = roleFilter === "all" ? true : log.userRole === roleFilter

          return matchSearch && matchRole
        })
        .sort(
          (a, b) =>
            new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
        ),
    [scopedLogs, search, roleFilter]
  )

  return (
    <div className="flex flex-col gap-6">
      <PageHeader
        title="Activity Logs"
        description={
          isAdmin
            ? "System-wide audit trail for all key actions"
            : "Utility-level audit trail for governance and oversight"
        }
      />

      {/* Filters */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Search by action, user, entity or details..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9"
          />
        </div>
        <div className="flex items-center gap-2">
          <Filter className="hidden h-4 w-4 text-muted-foreground sm:block" />
          <Select
            value={roleFilter}
            onValueChange={(v) => setRoleFilter(v as typeof roleFilter)}
          >
            <SelectTrigger className="w-44">
              <SelectValue placeholder="Role" />
            </SelectTrigger>
            <SelectContent>
              {ROLE_FILTERS.map((r) => (
                <SelectItem key={r.value} value={r.value}>
                  {r.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      <Card>
        <CardContent className="p-0">
          <ScrollArea className="h-[540px]">
            {filtered.length === 0 ? (
              <div className="flex flex-col items-center justify-center px-6 py-16 text-center text-sm text-muted-foreground">
                <ScrollText className="mb-3 h-8 w-8 text-muted-foreground/40" />
                No activity logs found for the selected filters.
              </div>
            ) : (
              <div className="divide-y">
                {filtered.map((log) => (
                  <div
                    key={log.id}
                    className="flex flex-col gap-2 px-6 py-4 text-sm hover:bg-muted/40"
                  >
                    <div className="flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2">
                        <Badge variant="outline" className="text-[11px]">
                          {log.entity}
                        </Badge>
                        <span className="font-medium">{log.action}</span>
                      </div>
                      <div className="flex items-center gap-2 text-xs text-muted-foreground">
                        <Clock3 className="h-3.5 w-3.5" />
                        <span>
                          {new Date(log.timestamp).toLocaleString("en-ZA")}
                        </span>
                      </div>
                    </div>
                    <div className="flex flex-wrap items-center justify-between gap-2">
                      <div className="flex items-center gap-2 text-xs text-muted-foreground">
                        <UserCircle2 className="h-3.5 w-3.5" />
                        <span>{log.userName}</span>
                        <span className="mx-1.5 h-1 w-1 rounded-full bg-muted-foreground/40" />
                        <span className="capitalize">{log.userRole.replace("_", " ")}</span>
                      </div>
                      {(log.utilityId || log.dmaId) && (
                        <div className="flex items-center gap-2 text-[11px] text-muted-foreground">
                          {log.utilityId && (
                            <span className="rounded-full bg-blue-50 px-2 py-0.5 text-blue-700">
                              Utility: {log.utilityId}
                            </span>
                          )}
                          {log.dmaId && (
                            <span className="rounded-full bg-emerald-50 px-2 py-0.5 text-emerald-700">
                              DMA: {log.dmaId}
                            </span>
                          )}
                        </div>
                      )}
                    </div>
                    <p className="text-xs text-muted-foreground leading-relaxed">
                      {log.details}
                    </p>
                  </div>
                ))}
              </div>
            )}
          </ScrollArea>
        </CardContent>
      </Card>
    </div>
  )
}

